INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-814ced5a-moex-00336', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「與其（甲）□□□□，不如（乙）□□□□，如果能早做準備，就不怕悔之晚矣了！」 上文空格適合填入的語詞是：', '["甲：亡羊補牢，乙：防患未然", "甲：倉倉惶惶，乙：好整以暇", "甲：江心補漏，乙：刻木求舟", "甲：曲突徙薪，乙：有備無患 甲：臨渴掘井，乙：未雨綢繆"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00337', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「如同彩虹應許晴天一樣，知更鳥也應許著一個夏天。在我們的生活當中，總是充滿著這樣的應許與 記號。」 下列選項何者也有上文所說的「應許與記號」？', '["春風不解意，先遣柳條青", "夕陽無限好，只是近黃昏", "山窮水複疑無路，柳暗花明又一村", "竹外桃花三二枝，春江水暖鴨先知 暮雲收盡溢清寒，銀漢無聲轉玉盤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00338', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「貓的語言和行為完全來自人類的詮釋和猜測，因此不免於人類心靈或慾望的投射。愛貓人總警惕世 人勿以人類的習慣和立場對待貓。有趣的是，所有的書寫都來自『誤解』或『不完全的理解』，因為 神祕和不可解，才產生差異和想像，一旦跟貓『同化』，沒有意識到彼此的異質性時，一切都成為理 所當然，就再也寫不出，或者不需要這些文字了。因此閱讀這本書最大的樂趣便是一個既『貓』又『人』 的書寫角度。」 根據上文，下列敘述正確的是：', '["「這本書」的書寫內容應該與貓有關", "「這本書」的作者理解貓所有的情感", "世人經常以自己的習慣和立場對待貓", "愛貓人希望大家能推己及人的看待貓 人類常以猜想去理解貓的語言與行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00339', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「半瓶子的水才會叮咚作響；清淺的小溪才時聞潺潺的水聲。滿瓶的水和巨河大川，可都是寂然無聲 的。也有人說：『會咬人的狗不吠。』那躁急愛叫的狗，也無非是虛張聲勢罷了！一頭真正的名犬， 在遇到獵物時，一定是先察言觀色，而後動如脫兔，迅捷有若閃電，獵物自然就一舉成擒了。想來， 在這個社會上，只有平庸的人才常自以為是，唯恐天下人不知道自己，所以時時自我吹噓，結果適得 其反，更惹人厭煩。反倒是那些有著真才實學的人，沉默謙抑，常自以為不足；更由於專心致志於工 作或研究，既無暇也不屑誇耀自己。他無需宣傳，然而，出色的成績有目共睹，令人景仰。讓我們學 著在該說話的時候說，不該說話的時候閉口無言，使所有的浮誇虛榮遠離，做一個實事求是的人。」 根據上文，比喻真才實學的是：', '["滿瓶的水", "巨河大川", "會咬人的狗", "出色的成績 專心致志於工作"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00340', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '承上題，下列選項符合本文旨意的是：', '["寧鳴而死，不默而生", "時然後言，人不厭其言", "君子欲訥於言，而敏於行", "吉人之辭寡，躁人之辭多 河海不擇細流，故能就其深"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00341', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「機器人或許能當創意總監，但永遠沒辦法變李安。不論是電影、音樂或廣告行銷，真正能打動人心 的內容，是數據分析不來的。感動人的才情和原創不是分析出來的，分析只能運用過去事件預估未來； 根據過去成功而創造的未來，是一種重現和重組，但不是一種原創。人類的情感、靈魂、慾望和道德， 持續需要原創的洗滌和刺激，提供新的角度、新的感動、新的形式。」 上文是關於機器人可能在未來取代許多工作的討論，依據上文內容判斷，符合文中敘述的是：', '["機器人可如同人類擁有自我意識和自我道德", "創意的價值和可貴，無法被分析和數據取代", "機器人在未來十年，將與各行各業平起平坐", "基於邏輯和過去經驗產生的重組，超越原創 原創的不可複製和重要性，在未來更顯重要"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00342', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「自己的房間利用電話、電腦和電傳插入了繁複的世界體系，化身為一塊記錄著我的思路的電路板， 通向一個新的時空，或者被另一個房間所拒斥。關閉了那些由電子組構的，無形無影的門扉和窗口， 剩下的是一個封閉的自我。粉刷牆壁的時候，像是粉刷自己的情緒，一層白漆乾了再漆一層，一層白 色堆疊在白色之上，仍然匯融成同一種不可抗拒的白色。」 有關本文主旨說明適當的是：', '["透過房間來象徵科技產品形成的宰制", "科技無遠弗屆，未來人類將無法自絕於外", "強調網路社群媒體須無阻礙共享的迫切性", "人們相信憑藉科技產品能打破空間的限制向外延伸 重複出現的「白色」象徵生活中封閉與寂寞的情感"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00343', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '西方諺語：「只要有心學習，不怕找不到老師」，下列符合此意旨的是：', '["敏而好學，不恥下問", "溫故而知新，可以為師矣", "巫醫、樂師、百工之人，不恥相師", "由，誨女知之乎？知之為知之，不知為不知，是知也 三人行，必有我師焉。擇其善者而從之，其不善者而改之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00344', 'locality-814ced5a', 'locality-814ced5a-moex-110-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「禮」的精神在於將內心真誠之情感表現為外在的動作儀式，下列選項何者符合這樣的意涵？', '["人而不仁，如禮何", "辭讓之心，禮之端也", "禮者，因人之情而為之節文", "夫禮者，陰陽之際也，百事之會也 禮者所以守尊卑之經、強弱之稱者也"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "446a8cd8f77b", "answer_pdf_sha1": "ad20df8aa8a5", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00345', 'locality-814ced5a', 'locality-814ced5a-moex-110-c2172ccd', 'sub-locality-814ced5a-04', NULL, 'single_choice', '下列何種詮釋資料（metadata）類型，可用於智慧財產權與複製追蹤？', '["描述型", "管理型", "保存型", "技術型"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:30+00:00", "source_pdf_sha1": "9a4c61f9d8e9", "answer_pdf_sha1": "f7635ca03da9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "506", "s": "0311", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "圖書館學大意", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
